#include <stdio.h>
int max(int a, int b){
    int maxim;
    return maxim=(a>=b)?a:b;
}

int main(void)
{
    int a,b,c,d, misha, vasya;
    scanf("%d %d %d %d", &a,&b,&c,&d);
    misha = max((3*a)/10 ,a- ((a*c)/250));
    vasya = max((3*b)/10 ,b-((b*d)/250));
    if(misha>vasya) printf("Misha");
    else if(misha<vasya) printf("Vasya");
    else printf("Tie");

    return 0;
