use std::io;
use std::str::FromStr;

fn get_nums() -> (usize, usize, usize, usize) {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    let v = input
        .trim()
        .split_whitespace()
        .map(|s| usize::from_str(s).unwrap())
        .collect::<Vec<_>>();

    (v[0], v[1], v[2], v[3])
}

fn main() {
    let (a, b, c, d) = get_nums();

    let misha = std::cmp::max(3 * a / 10, a - a / 250 * c);
    let vasya = std::cmp::max(3 * b / 10, b - b / 250 * d);

    if misha > vasya {
        println!("Misha");
    } else if misha < vasya {
        println!("Vasya");
    } else {
        println!("Tie");
    }
}
